  1	import React, { FC, useState } from 'react';
  2	
  3	import { IoK8sApiCoreV1Pod } from '@kubevirt-ui/kubevirt-api/kubernetes';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import { modelToGroupVersionKind, PodModel } from '@kubevirt-utils/models';
  6	import { createSecret } from '@kubevirt-utils/resources/secret/utils';
  7	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
  8	import { getRandomChars } from '@kubevirt-utils/utils/utils';
  9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Alert,
 12	  AlertVariant,
 13	  FormGroup,
 14	  Stack,
 15	  StackItem,
 16	  TextInput,
 17	} from '@patternfly/react-core';
 18	
 19	import TabModal from '../TabModal/TabModal';
 20	
 21	import { ALREADY_CREATED_ERROR_CODE } from './constants';
 22	import ShowProgress from './ShowProgress';
 23	import { createServiceAccount, createUploaderPod, exportInProgress } from './utils';
 24	import ViewPodLogLink from './ViewPodLogLink';
 25	
 26	import './export-modal.scss';
 27	
 28	type ExportModalProps = {
 29	  isOpen: boolean;
 30	  namespace: string;
 31	  onClose: () => void;
 32	  pvcName: string;
 33	  vmName?: string;
 34	};
 35	
 36	const ExportModal: FC<ExportModalProps> = ({ isOpen, namespace, onClose, pvcName, vmName }) => {
 37	  const { t } = useKubevirtTranslation();
 38	
 39	  const [registryName, setRegistryName] = useState(() => `registry-${getRandomChars()}`);
 40	  const [username, setUsername] = useState('');
 41	  const [password, setPassword] = useState('');
 42	  const [destination, setDestination] = useState('');
 43	
 44	  const [createdPod, setCreatedPod] = useState<IoK8sApiCoreV1Pod>();
 45	
 46	  const [uploadPod] = useK8sWatchResource<IoK8sApiCoreV1Pod>(
 47	    createdPod
 48	      ? {
 49	          groupVersionKind: modelToGroupVersionKind(PodModel),
 50	          name: getName(createdPod),
 51	          namespace: getNamespace(createdPod),
 52	        }
 53	      : null,
 54	  );
 55	
 56	  const uploadInProgress = exportInProgress(uploadPod || createdPod);
 57	
 58	  return (
 59	    <TabModal
 60	      onSubmit={async () => {
 61	        const secretName = `registry-secret-${getRandomChars()}`;
 62	
 63	        try {
 64	          await createServiceAccount(namespace);
 65	        } catch (error) {
 66	          if (error.code !== ALREADY_CREATED_ERROR_CODE) throw error;
 67	        }
 68	
 69	        await createSecret({ namespace, password, secretName, username });
 70	        const pod = await createUploaderPod({
 71	          destination,
 72	          namespace,
 73	          secretName,
 74	          vmName,
 75	          volumeName: pvcName,
 76	        });
 77	
 78	        setCreatedPod(pod);
 79	      }}
 80	      actionItemLink={<ViewPodLogLink pod={uploadPod} />}
 81	      closeOnSubmit={false}
 82	      headerText={t('Upload to registry')}
 83	      isDisabled={uploadInProgress}
 84	      isLoading={uploadInProgress}
 85	      isOpen={isOpen}
 86	      onClose={onClose}
 87	      submitBtnText={t('Upload')}
 88	    >
 89	      <Stack className="kv-exportmodal" hasGutter>
 90	        <Alert
 91	          title={t(
 92	            'Before uploading to a registry, it is recommended to remove any private information from the image',
 93	          )}
 94	          isInline
 95	          variant={AlertVariant.warning}
 96	        ></Alert>
 97	        <StackItem>
 98	          <FormGroup fieldId="registryName" isRequired label={t('Name')}>
 99	            <TextInput
100	              id="registryName"
101	              onChange={(_, value: string) => setRegistryName(value)}
102	              type="text"
103	              value={registryName}
104	            />
105	          </FormGroup>
106	        </StackItem>
107	        <StackItem>
108	          <FormGroup fieldId="destination" isRequired label={t('Destination')}>
109	            <TextInput
110	              id="destination"
111	              onChange={(_, value: string) => setDestination(value)}
112	              type="text"
113	              value={destination}
114	            />
115	          </FormGroup>
116	        </StackItem>
117	        <StackItem>
118	          <FormGroup fieldId="username" isRequired label={t('Username')}>
119	            <TextInput
120	              id="username"
121	              onChange={(_, value: string) => setUsername(value)}
122	              type="text"
123	              value={username}
124	            />
125	          </FormGroup>
126	        </StackItem>
127	        <StackItem>
128	          <FormGroup fieldId="password" isRequired label={t('Password')}>
129	            <TextInput
130	              id="password"
131	              onChange={(_, value: string) => setPassword(value)}
132	              type="password"
133	              value={password}
134	            />
135	          </FormGroup>
136	        </StackItem>
137	        <StackItem>
138	          <ShowProgress uploadPod={uploadPod} />
139	        </StackItem>
140	      </Stack>
141	    </TabModal>
142	  );
143	};
144	
145	export default ExportModal;

